const styles = `
/* typedoc-theme-fresh */

/* @view-transition {
  navigation: auto;
} */

:root {
  --light-color-background: #fafafe;
  --light-color-background-active: #eaeced;
  --light-color-text: #222222;
  --light-color-text-aside: #5e5e5e;

  --dark-color-background: #1a1a1c;
  --dark-color-background-active: #2f2f2b;
  --dark-color-text: #dfdfd6;
  --dark-color-text-aside: #b0b0b0;

  --dim-header-height: 2.5rem;
  --dim-footer-height: 0px;

  --light-code-background: #ffffff18;
  --dark-code-background: #00000018;
}

body {
  padding: 0;
  margin: 0;
  & > .container.container-main {
    margin: 0 auto;
    margin-top: var(--dim-header-height);
    --dim-container-main-margin-y: 0px;
  }
}

@media (prefers-color-scheme: light) {
  ::selection {
    background-color: #11111a20;
  }
}

@media (prefers-color-scheme: dark) {
  ::selection {
    background-color: #bbbbff48;
  }
}

:root[data-theme="light"] {
  ::selection {
    background-color: #11111a20;
  }
}

:root[data-theme="dark"] {
  ::selection {
    background-color: #bbbbff48;
  }
}

h1, h2, h3, h4, h5, h6 {
  font-weight: 500;
}

.tsd-page-toolbar {
  position: fixed;
  background: linear-gradient(
    to bottom,
    color-mix(in srgb, var(--color-background) 80%, transparent) 60%,
    transparent
  );
  backdrop-filter: blur(2px);
  border-bottom: none;

  .title {
    font-weight: 500;
    font-size: 18px;
    white-space: nowrap;
    text-overflow: ellipsis;
    overflow: hidden;
    min-width: 0;
    margin-right: auto;

    &:hover {
      color: var(--color-contrast-text);
      text-decoration: none;
    }
  }

  .tsd-theme-toggle {
    display: flex;
    position: relative;
    margin-right: 12px;
    color: var(--color-text-aside);
    
    select {
      cursor: pointer;
      border: 1px solid var(--color-background-active);
      border-radius: 4px;
      padding: 6px 8px;
      padding-left: 32px;  /* Space for the icon */
      font-size: 14px;
      background: transparent;
      transition: background-color 200ms;
      color: var(--color-text-aside);
      
      /* for Firefox and Chrome: these are inconsistent */
      -moz-appearance: none;
      -webkit-appearance: none;
      
      &:hover {
        background-color: var(--color-background-active);
      }
    }
  }
}

.tsd-widget {
  display: flex;
  align-items: center;
  height: auto;
  width: auto;
  padding: 4px;
  font-size: 14px;
  border-radius: 4px;
  transition: background-color 200ms;
  color: var(--color-text-aside);
  opacity: 100%;

  &:hover {
    background-color: var(--color-background-active);
  }
}

#tsd-search-results {
  & > li {
    padding-inline: 6px;
    transition: background-color 200ms;
  }

  a:hover {
    text-decoration: none;
  }
}

.col-content {
  overflow: hidden;
  padding-block: 24px;

  & > .tsd-typography {
    padding-bottom: 24px;
  }
}

.col-sidebar {
  top: var(--dim-header-height);  /* Relevant for tablet layout. */
}

.site-menu {
  top: var(--dim-header-height);
  padding-block: 24px;
  box-sizing: border-box;
}

.page-menu {
  top: var(--dim-header-height);
  padding-block: 48px 24px;
  box-sizing: border-box;
}

.tsd-navigation,
.tsd-page-navigation {
  > details {
    margin-bottom: 8px;
  }

  a {
    border-radius: 4px;
    padding-inline: 6px;
    margin-bottom: 2px;
  }
  a:hover {
    text-decoration: none;
    background-color: var(--color-background-active);
  }
  a.current {
    background-color: var(--color-background-active);
    span {
      color: var(--color-contrast-text);
    }
  }
}

.tsd-navigation {
  & > a {
    /* Top-level navigation anchor. */
    margin-block: 16px;
    font-size: 18px;
    background: transparent !important;
    padding: 0;
    
    &:hover {
      color: var(--color-contrast-text);
    }
  }
}

.tsd-page-navigation {
  border-left: 1px solid var(--color-background-active);
  padding-left: 4px;
  padding-block: 4px;
}

.tsd-page-navigation-section {
  & > summary > svg {
    margin-right: 0;
  }
  & > div {
    margin-left: 24px;
  }
}

.tsd-page-title {
  color: var(--color-contrast-text);
}

h1 > code.tsd-tag {
  margin-left: 12px;
}

code.tsd-tag {
  display: inline-block;
  transform: translateY(-0.1em);
  background: var(--color-background-secondary);
  border: 0;
  border-radius: 8px;
  padding: 2px 4px;
}

.tsd-breadcrumb {
  margin-bottom: 12px;
  li:after {
    content: " › ";
    opacity: 0.4;
  }
  li:last-of-type::after {
    content: "";
  }
}

.tsd-signature,
.tsd-signatures .tsd-signature {
  border: 0;
  border-radius: 8px;
  background: var(--color-background-secondary);
  font-weight: 500;
  padding: 10px 8px;
  line-height: 1.3;
}

.tsd-anchor-icon {
  color: var(--color-text-aside);
  padding-bottom: 1px;
}

.tsd-kind-icon {
  filter: grayscale(0.5) opacity(0.8);
}

/* Accordion icon */
.tsd-accordion-summary > svg {
  color: var(--color-text-aside);
  opacity: 50%;
  stroke-width: 1px;
  transition: transform 200ms ease-in-out;
}

.tsd-accordion-summary > svg:has(+ h2) {
  height: 24px;
  width: 24px;
}

/* Desktop sizing */
@media (min-width: 1200px) {
  .container-main {
    grid-template-columns: minmax(0, 1.1fr) minmax(0, 2.5fr) minmax(0, 17rem);
  }

  .site-menu {
    padding-right: 8px;
  }
  .page-menu {
    padding-left: 24px;
  }

  .tsd-widget.menu {
    display: none;
  }
}

/* Tablet sizing */
@media (min-width: 770px) and (max-width: 1199px) {
  .page-menu {
    padding-block: 24px 24px;
  }
  .site-menu {
    padding-block: 0 24px;
    margin-top: 0;
  }

  .tsd-widget.menu {
    display: none;
  }

  .lg-show {
    display: none !important;
  }
}

/* Mobile sizing */
@media (max-width: 769px) {
  .page-menu {
    display: none;
  }
  .site-menu {
    padding: 0;
  }

  .container {
    padding: 0 1rem;
  }

  .has-menu .col-sidebar {
    padding: 0 1rem;
    max-height: 100dvh;
  }

  .lg-show {
    display: none !important;
  }
  .md-show {
    display: none !important;
  }
}
`;
